import os
import requests
import json
import re
import math
import hashlib
import threading
from datetime import datetime
from typing import List, Union, Generator, Iterator
from pydantic import BaseModel, Field

try:
    from bs4 import BeautifulSoup
except ImportError:
    BeautifulSoup = None

try:
    from pptx import Presentation
    from pptx.util import Inches, Pt
    from pptx.dml.color import RGBColor
    from pptx.enum.text import PP_ALIGN
    import io, base64

    PPTX_AVAILABLE = True
except ImportError:
    PPTX_AVAILABLE = False

# ================================================================
# ChromaDB — основное хранилище памяти.
# Контейнер gpthub-memory доступен по http://gpthub-memory:8000
# из сети gpthub_default. Volume: D:/gpthub/chroma_data → персистентный.
# Fallback: JSON-файлы в /app/pipelines/memories если ChromaDB недоступен.
# ================================================================
try:
    import chromadb

    CHROMADB_AVAILABLE = True
except ImportError:
    CHROMADB_AVAILABLE = False


class MemoryManager:
    # ChromaDB
    CHROMA_HOST = "gpthub-memory"
    CHROMA_PORT = 8000

    # JSON fallback paths
    _CANDIDATE_DIRS = [
        "/app/pipelines/memories",
        "/tmp/gpthub_memories",
    ]

    # ----------------------------------------------------------------
    # ФИКС БАГ: MIN_SIMILARITY снижен с 0.7 → 0.35
    # bge-m3 для семантически близких фраз возвращает 0.40–0.60,
    # при пороге 0.7 почти всё фильтровалось как нерелевантное.
    # ----------------------------------------------------------------
    MIN_SIMILARITY = 0.35

    # Порог дедупликации: не сохраняем если cosine > 0.92 (почти дубль)
    DEDUP_THRESHOLD = 0.92

    MAX_MEMORIES = 1000
    TOP_K = 5
    EMBED_MODEL = "bge-m3"

    _write_locks: dict = {}
    _locks_lock = threading.Lock()

    # Кэш ChromaDB-клиентов (чтобы не создавать новое соединение на каждый запрос)
    _chroma_clients: dict = {}
    _clients_lock = threading.Lock()

    def __init__(self, api_key: str, base_url: str):
        self.api_key = api_key
        self.base_url = base_url.rstrip("/")
        self._json_dir = self._find_json_dir()
        self._chroma_ok = self._test_chroma()

    @classmethod
    def _find_json_dir(cls) -> str:
        for path in cls._CANDIDATE_DIRS:
            try:
                os.makedirs(path, exist_ok=True)
                test = os.path.join(path, ".write_test")
                with open(test, "w") as f:
                    f.write("ok")
                os.remove(test)
                return path
            except Exception:
                continue
        os.makedirs("/tmp/gpthub_memories", exist_ok=True)
        return "/tmp/gpthub_memories"

    def _test_chroma(self) -> bool:
        if not CHROMADB_AVAILABLE:
            return False
        try:
            client = chromadb.HttpClient(
                host=self.CHROMA_HOST,
                port=self.CHROMA_PORT,
                settings=chromadb.config.Settings(anonymized_telemetry=False),
            )
            client.heartbeat()
            return True
        except Exception:
            return False

    def _get_chroma_collection(self, user_id: str):
        """Возвращает ChromaDB-коллекцию для пользователя. Одна коллекция = один пользователь."""
        safe = hashlib.md5(user_id.encode()).hexdigest()[:20]
        col_name = f"mem_{safe}"
        try:
            client = chromadb.HttpClient(
                host=self.CHROMA_HOST,
                port=self.CHROMA_PORT,
                settings=chromadb.config.Settings(anonymized_telemetry=False),
            )
            # cosine distance: distance = 1 - similarity
            col = client.get_or_create_collection(
                col_name,
                metadata={"hnsw:space": "cosine"},
            )
            return col
        except Exception:
            return None

    @staticmethod
    def _cosine(a: list, b: list) -> float:
        if not a or not b or len(a) != len(b):
            return 0.0
        dot = sum(x * y for x, y in zip(a, b))
        norm_a = math.sqrt(sum(x * x for x in a))
        norm_b = math.sqrt(sum(x * x for x in b))
        if norm_a == 0 or norm_b == 0:
            return 0.0
        return dot / (norm_a * norm_b)

    def _embed(self, text: str) -> list:
        try:
            res = requests.post(
                f"{self.base_url}/embeddings",
                headers={
                    "Authorization": f"Bearer {self.api_key}",
                    "Content-Type": "application/json",
                },
                json={"model": self.EMBED_MODEL, "input": text[:2000]},
                timeout=15,
            )
            return res.json()["data"][0]["embedding"]
        except Exception:
            return []

    # ----------------------------------------------------------------
    # ChromaDB: add / retrieve
    # ----------------------------------------------------------------

    def _chroma_add(
        self, user_id: str, mem_type: str, content: str, embedding: list
    ) -> bool:
        col = self._get_chroma_collection(user_id)
        if col is None:
            return False
        try:
            if embedding:
                # Проверка на дубль через query
                results = col.query(
                    query_embeddings=[embedding],
                    n_results=1,
                    include=["distances"],
                )
                dists = results.get("distances", [[]])[0]
                # cosine distance < (1 - DEDUP_THRESHOLD) означает почти одинаковый факт
                if dists and dists[0] < (1.0 - self.DEDUP_THRESHOLD):
                    return False  # дубль — пропускаем

            mem_id = hashlib.md5(
                f"{user_id}{content}{datetime.now().isoformat()}".encode()
            ).hexdigest()[:16]

            col.add(
                ids=[mem_id],
                embeddings=[embedding] if embedding else None,
                documents=[content],
                metadatas=[
                    {
                        "type": mem_type,
                        "user_id": user_id,
                        "created_at": datetime.now().isoformat(),
                    }
                ],
            )
            return True
        except Exception:
            return False

    def _chroma_retrieve(self, user_id: str, query: str, top_k: int) -> list:
        col = self._get_chroma_collection(user_id)
        if col is None:
            return []
        try:
            query_emb = self._embed(query)
            result_docs = []
            seen_ids = set()

            if query_emb:
                # Семантический поиск
                # distance threshold = 1 - MIN_SIMILARITY
                dist_threshold = 1.0 - self.MIN_SIMILARITY
                results = col.query(
                    query_embeddings=[query_emb],
                    n_results=min(top_k, 10),
                    include=["documents", "distances", "metadatas"],
                )
                ids = results.get("ids", [[]])[0]
                docs = results.get("documents", [[]])[0]
                dists = results.get("distances", [[]])[0]

                for mid, doc, dist in zip(ids, docs, dists):
                    if dist <= dist_threshold:
                        seen_ids.add(mid)
                        result_docs.append(doc)

            # Recency boost: последние 3 факта всегда добавляем
            all_data = col.get(
                where={"type": "fact"},
                include=["documents", "metadatas"],
            )
            all_ids = all_data.get("ids", [])
            all_docs = all_data.get("documents", [])
            all_meta = all_data.get("metadatas", [])

            # Сортируем по created_at DESC
            triples = list(zip(all_meta, all_docs, all_ids))
            triples.sort(key=lambda x: x[0].get("created_at", ""), reverse=True)

            for meta, doc, mid in triples[:3]:
                if mid not in seen_ids and len(result_docs) < top_k + 3:
                    seen_ids.add(mid)
                    result_docs.append(doc)

            return result_docs[:top_k]
        except Exception:
            return []

    # ----------------------------------------------------------------
    # JSON fallback: add / retrieve
    # ----------------------------------------------------------------

    def _get_write_lock(self, user_id: str) -> threading.Lock:
        with self._locks_lock:
            if user_id not in self._write_locks:
                self._write_locks[user_id] = threading.Lock()
            return self._write_locks[user_id]

    def _json_path(self, user_id: str) -> str:
        safe = hashlib.md5(user_id.encode()).hexdigest()
        return os.path.join(self._json_dir, f"{safe}.json")

    def _json_load(self, user_id: str) -> dict:
        path = self._json_path(user_id)
        if not os.path.exists(path):
            return {"user_id": user_id, "memories": []}
        try:
            with open(path, "r", encoding="utf-8") as f:
                return json.load(f)
        except Exception:
            return {"user_id": user_id, "memories": []}

    def _json_save(self, user_id: str, data: dict):
        lock = self._get_write_lock(user_id)
        path = self._json_path(user_id)
        tmp = path + ".tmp"
        with lock:
            try:
                with open(tmp, "w", encoding="utf-8") as f:
                    json.dump(data, f, ensure_ascii=False, indent=2)
                os.replace(tmp, path)
            except Exception:
                try:
                    os.remove(tmp)
                except Exception:
                    pass

    def _json_add(
        self, user_id: str, mem_type: str, content: str, embedding: list
    ) -> bool:
        data = self._json_load(user_id)
        memories = data["memories"]
        for m in memories:
            if self._cosine(m.get("embedding", []), embedding) > self.DEDUP_THRESHOLD:
                return False
        mem_id = hashlib.md5(
            f"{user_id}{content}{datetime.now().isoformat()}".encode()
        ).hexdigest()[:12]
        memories.append(
            {
                "id": mem_id,
                "type": mem_type,
                "content": content,
                "embedding": embedding,
                "created_at": datetime.now().isoformat(),
            }
        )
        if len(memories) > self.MAX_MEMORIES:
            memories.sort(key=lambda x: x.get("created_at", ""))
            memories = memories[-self.MAX_MEMORIES :]
        data["memories"] = memories
        self._json_save(user_id, data)
        return True

    def _json_retrieve(self, user_id: str, query: str, top_k: int) -> list:
        data = self._json_load(user_id)
        memories = data.get("memories", [])
        if not memories:
            return []

        query_emb = self._embed(query)
        seen_ids = set()
        result = []

        if query_emb:
            scored = []
            for m in memories:
                sim = self._cosine(m.get("embedding", []), query_emb)
                if sim >= self.MIN_SIMILARITY:
                    scored.append((sim, m))
            scored.sort(key=lambda x: x[0], reverse=True)
            for _, m in scored[:top_k]:
                seen_ids.add(m["id"])
                result.append(m["content"])

        # Recency boost
        facts = sorted(
            [m for m in memories if m.get("type") == "fact"],
            key=lambda x: x.get("created_at", ""),
            reverse=True,
        )
        for m in facts[:3]:
            if m["id"] not in seen_ids and len(result) < top_k + 3:
                seen_ids.add(m["id"])
                result.append(m["content"])

        if not result:
            return [m["content"] for m in memories[-top_k:]]

        return result

    # ----------------------------------------------------------------
    # Публичный интерфейс
    # ----------------------------------------------------------------

    def add(self, user_id: str, mem_type: str, content: str) -> bool:
        content = content.strip()
        if not content or len(content) < 10:
            return False
        embedding = self._embed(content)

        if self._chroma_ok:
            return self._chroma_add(user_id, mem_type, content, embedding)
        else:
            return self._json_add(user_id, mem_type, content, embedding)

    def retrieve(self, user_id: str, query: str, top_k: int = None) -> list:
        top_k = top_k or self.TOP_K
        if self._chroma_ok:
            return self._chroma_retrieve(user_id, query, top_k)
        else:
            return self._json_retrieve(user_id, query, top_k)

    def extract_from_exchange(
        self,
        user_id: str,
        api_key: str,
        base_url: str,
        router_model: str,
        user_message: str,
        assistant_message: str,
    ):
        """
        КЛЮЧЕВОЕ ИСПРАВЛЕНИЕ:
        Раньше этот метод вызывался В НАЧАЛЕ следующего запроса, смотря на messages[:-1].
        В новом чате messages содержит только 1 сообщение → messages[:-1] = [] →
        факты из старого чата НИКОГДА не сохранялись.

        Теперь метод вызывается ПОСЛЕ завершения стрима (в _stream_and_save),
        передавая текущий user_message и накопленный assistant_message.
        Это гарантирует сохранение фактов даже из одиночного обмена.
        """
        if not user_message or not assistant_message:
            return
        if len(assistant_message) < 30:
            return

        prompt = (
            "Проанализируй диалог ниже и извлеки ТОЛЬКО объективно полезные факты.\n"
            "Верни JSON без markdown-обёртки в формате:\n"
            '{"facts": ["факт 1", "факт 2"], "summaries": ["резюме задачи 1"]}\n\n'
            "Правила:\n"
            '- В "facts": личные данные пользователя (имя, профессия, язык, страна, предпочтения, '
            "навыки, проекты над которыми работает, используемые технологии/инструменты).\n"
            '- В "summaries": кратко (1 предложение) что было сделано/решено, только если задача была '
            "нетривиальной (написан код, создана презентация, найдена информация и т.д.).\n"
            "- Если фактов нет — верни пустые списки.\n"
            "- Не добавляй очевидное (например 'пользователь написал сообщение').\n"
            "- Факты формулируй от третьего лица: 'Пользователь работает с Python'.\n\n"
            f"Пользователь: {user_message[:500]}\n\n"
            f"Ассистент: {assistant_message[:800]}\n\n"
            "JSON:"
        )

        mem_manager = self

        def _run():
            try:
                res = requests.post(
                    f"{base_url}/chat/completions",
                    headers={"Authorization": f"Bearer {api_key}"},
                    json={
                        "model": router_model,
                        "messages": [{"role": "user", "content": prompt}],
                        "max_tokens": 400,
                        "temperature": 0.1,
                    },
                    timeout=20,
                )
                raw = res.json()["choices"][0]["message"]["content"]
                raw = re.sub(r"```json\s*", "", raw)
                raw = re.sub(r"```\s*", "", raw)
                raw = raw.strip()

                json_match = re.search(r"\{[\s\S]*\}", raw)
                if json_match:
                    raw = json_match.group(0)

                extracted = json.loads(raw)
                facts = extracted.get("facts", [])
                summaries = extracted.get("summaries", [])

                for fact in facts:
                    if isinstance(fact, str) and len(fact) > 10:
                        mem_manager.add(user_id, "fact", fact)
                for summary in summaries:
                    if isinstance(summary, str) and len(summary) > 15:
                        mem_manager.add(user_id, "summary", summary)

            except Exception:
                pass

        t = threading.Thread(target=_run, daemon=True)
        t.start()

    def format_for_prompt(self, memories: list) -> str:
        if not memories:
            return ""
        lines = "\n".join(f"• {m}" for m in memories)
        return (
            "=== ДОЛГОСРОЧНАЯ ПАМЯТЬ ===\n"
            f"{lines}\n"
            "=== КОНЕЦ ПАМЯТИ ===\n\n"
            "ИНСТРУКЦИЯ ПО ИСПОЛЬЗОВАНИЮ ПАМЯТИ:\n"
            "1. Если пользователь спрашивает конкретный факт о себе (например, 'какой мой любимый цвет?'), "
            "ОБЯЗАТЕЛЬНО бери ответ из памяти выше.\n"
            "2. Если пользователь просит 'еще', 'другой' или 'новый' (например, 'расскажи еще факт'), "
            "тебе ЗАПРЕЩЕНО использовать те факты, которые уже есть в блоке памяти. Найди или придумай совершенно новый."
        )


