    def _get_presentation_structure(self, valves, topic: str) -> dict:
        prompt = (
            f"Создай структуру презентации на тему: {topic}\n\n"
            "Верни ТОЛЬКО валидный JSON без markdown-обёртки (без ```json), в формате:\n"
            '{"title": "Заголовок презентации", "slides": ['
            '{"title": "Заголовок слайда", "bullets": ["пункт 1", "пункт 2", "пункт 3"]}]}\n'
            "Количество слайдов: 6-8. Первый — вводный, последний — выводы. "
            "Пункты краткие, по 1 предложению. Язык: русский."
        )
        try:
            res = requests.post(
                f"{valves.MWS_BASE_URL}/chat/completions",
                headers={"Authorization": f"Bearer {valves.MWS_API_KEY}"},
                json={
                    "model": valves.TEXT_MODEL,
                    "messages": [{"role": "user", "content": prompt}],
                    "max_tokens": 2000,
                    "temperature": 0.7,
                },
                timeout=60,
            )
            raw = res.json()["choices"][0]["message"]["content"]
            raw = re.sub(r"```json\s*", "", raw)
            raw = re.sub(r"```\s*", "", raw)
            return json.loads(raw.strip())
        except Exception as e:
            return {"error": str(e)}

    def _build_pptx_base64(self, structure: dict) -> str:
        prs = Presentation()
        prs.slide_width = Inches(13.33)
        prs.slide_height = Inches(7.5)

        COLOR_BG = RGBColor(0x0D, 0x1B, 0x2A)
        COLOR_HEADER = RGBColor(0x05, 0x10, 0x20)
        COLOR_ACCENT = RGBColor(0x00, 0xB4, 0xD8)
        COLOR_WHITE = RGBColor(0xFF, 0xFF, 0xFF)
        COLOR_BULLET = RGBColor(0xAD, 0xE8, 0xF4)

        def set_bg(slide):
            fill = slide.background.fill
            fill.solid()
            fill.fore_color.rgb = COLOR_BG

        def add_rect(slide, left, top, width, height, color):
            shape = slide.shapes.add_shape(
                1, Inches(left), Inches(top), Inches(width), Inches(height)
            )
            shape.fill.solid()
            shape.fill.fore_color.rgb = color
            shape.line.fill.background()
            return shape

        def add_text(
            slide,
            text,
            left,
            top,
            width,
            height,
            size=24,
            bold=False,
            color=None,
            align=PP_ALIGN.LEFT,
        ):
            tb = slide.shapes.add_textbox(
                Inches(left), Inches(top), Inches(width), Inches(height)
            )
            tf = tb.text_frame
            tf.word_wrap = True
            p = tf.paragraphs[0]
            p.alignment = align
            run = p.add_run()
            run.text = text
            run.font.size = Pt(size)
            run.font.bold = bold
            run.font.color.rgb = color if color else COLOR_WHITE

        slide = prs.slides.add_slide(prs.slide_layouts[6])
        set_bg(slide)
        add_rect(slide, 0, 3.3, 13.33, 0.06, COLOR_ACCENT)
        add_text(
            slide,
            structure.get("title", "Презентация"),
            1,
            2.3,
            11.33,
            1.5,
            size=40,
            bold=True,
            align=PP_ALIGN.CENTER,
        )
        add_text(
            slide,
            "GPTHub AI Workspace",
            1,
            6.5,
            11.33,
            0.7,
            size=16,
            color=COLOR_ACCENT,
            align=PP_ALIGN.CENTER,
        )

        for slide_data in structure.get("slides", []):
            slide = prs.slides.add_slide(prs.slide_layouts[6])
            set_bg(slide)
            add_rect(slide, 0, 0, 13.33, 1.3, COLOR_HEADER)
            add_rect(slide, 0, 0, 0.12, 1.3, COLOR_ACCENT)
            add_text(
                slide,
                slide_data.get("title", ""),
                0.25,
                0.18,
                12.8,
                1.0,
                size=28,
                bold=True,
            )

            y = 1.55
            for bullet in slide_data.get("bullets", []):
                add_rect(slide, 0.45, y + 0.14, 0.1, 0.1, COLOR_ACCENT)
                add_text(slide, bullet, 0.7, y, 12.0, 0.75, size=20, color=COLOR_BULLET)
                y += 0.85

        buf = io.BytesIO()
        prs.save(buf)
        buf.seek(0)
        return base64.b64encode(buf.read()).decode("utf-8")

    def _presentation_pipeline(self, valves, user_prompt):
        yield "📊 Генерирую структуру презентации...\n\n"

        structure = self._get_presentation_structure(valves, user_prompt)

        if "error" in structure:
            yield f"❌ Не удалось получить структуру от модели: {structure['error']}"
            return

        title = structure.get("title", "Презентация")
        slides = structure.get("slides", [])

        yield f"## 📋 {title}\n\n"
        for i, s in enumerate(slides, 1):
            yield f"**Слайд {i}: {s.get('title', '')}**\n"
            for b in s.get("bullets", []):
                yield f"- {b}\n"
            yield "\n"

        if not PPTX_AVAILABLE:
            yield (
                "⚠️ `python-pptx` не установлена — .pptx недоступен.\n"
                "Установите: `pip install python-pptx`\n\n"
                f"---\n> **Pipeline:** PRESENTATION → {valves.TEXT_MODEL}"
            )
            return

        yield "⚙️ Собираю .pptx...\n\n"
        try:
            b64 = self._build_pptx_base64(structure)
            safe_name = re.sub(r"[^\w\s-]", "", title).strip().replace(" ", "_")[:40]
            mime = "application/vnd.openxmlformats-officedocument.presentationml.presentation"
            yield (
                f"📥 **[Скачать {safe_name}.pptx](data:{mime};base64,{b64})**\n\n"
                f"---\n> **Pipeline:** PRESENTATION → {valves.TEXT_MODEL}"
            )
        except Exception as e:
            yield f"⚠️ Превью готово, .pptx не удалось собрать: {str(e)}\n\n"
            yield f"---\n> **Pipeline:** PRESENTATION → {valves.TEXT_MODEL}"

