    def classify_intent(self, valves, messages) -> str:
        raw_text = self._get_text(messages[-1].get("content", ""))
        text = self._clean_junk(raw_text)

        if not text:
            return "TEXT"

        system_prompt = (
            "Classify the user intent into exactly ONE word from this list:\n"
            "- IMAGE: user wants to generate/draw/create an image or picture\n"
            "- CODE: user wants to write, fix, explain, or review code/programming\n"
            "- PRESENTATION: user wants to create a presentation, slides, deck or PowerPoint file\n"
            "- SEARCH: user asks about current/real-time information: exchange rates, "
            "currency prices, weather, news, stocks, sports scores, recent events, "
            "anything that changes over time and requires up-to-date data\n"
            "- TEXT: everything else (general questions, writing, analysis, translation)\n"
            "Reply with ONE word only, no punctuation."
        )
        try:
            res = requests.post(
                f"{valves.MWS_BASE_URL}/chat/completions",
                headers={"Authorization": f"Bearer {valves.MWS_API_KEY}"},
                json={
                    "model": valves.ROUTER_MODEL,
                    "messages": [
                        {"role": "system", "content": system_prompt},
                        {"role": "user", "content": text},
                    ],
                    "max_tokens": 5,
                    "temperature": 0.0,
                },
            )
            intent = res.json()["choices"][0]["message"]["content"].upper().strip()
            return next(
                (
                    tag
                    for tag in ["IMAGE", "CODE", "PRESENTATION", "SEARCH"]
                    if tag in intent
                ),
                "TEXT",
            )
        except Exception:
            return "TEXT"

