    def pipe(
        self, body: dict, __user__: dict, __task__: str = None
    ) -> Union[str, Generator, Iterator]:
        valves = self.Valves(**body.get("valves", {}))
        messages = body.get("messages", [])
        last_content = messages[-1].get("content", "")

        has_img = (
            any(i.get("type") == "image_url" for i in last_content)
            if isinstance(last_content, list)
            else False
        )

        intent = self.classify_intent(valves, messages)
        raw_text = self._get_text(last_content)
        user_prompt_clean = self._clean_junk(raw_text)
        text_lower = user_prompt_clean.lower()

        for _ws_key in (
            "web_search_enabled",
            "web_search",
            "tool_ids",
            "tools",
            "citations",
        ):
            body.pop(_ws_key, None)

        # ================================================================
        # ДОЛГОСРОЧНАЯ ПАМЯТЬ — шаг 1: ТОЛЬКО извлечение и инъекция.
        # ИСПРАВЛЕНИЕ: извлечение фактов (extract_from_exchange) УБРАНО отсюда.
        # Раньше оно смотрело на messages[:-1] что не работало в новом чате.
        # Теперь извлечение происходит ПОСЛЕ стрима в _stream_and_save_memory.
        # ================================================================
        memory_context = ""
        mem = None
        user_id = __user__.get("id", "") if __user__ else ""

        if valves.MEMORY_ENABLED and user_id:
            mem = MemoryManager(valves.MWS_API_KEY, valves.MWS_BASE_URL)
            relevant = mem.retrieve(
                user_id, user_prompt_clean, top_k=MemoryManager.TOP_K
            )
            memory_context = mem.format_for_prompt(relevant)

        # ================================================================

        if has_img and intent != "IMAGE":
            if any(kw in text_lower for kw in self.STYLE_KEYWORDS):
                intent = "IMAGE"

        if has_img and intent == "IMAGE":
            wants_describe = any(kw in text_lower for kw in self.DESCRIBE_KEYWORDS)
            wants_style = any(kw in text_lower for kw in self.STYLE_KEYWORDS)
            if wants_describe and not wants_style:
                intent = "VISION_DESCRIBE"

        # === ПРЕЗЕНТАЦИЯ ===
        if intent == "PRESENTATION":
            return self._presentation_pipeline(valves, user_prompt_clean)

        # === Сбор дополнительного контекста ===
        extra_context = ""
        urls = re.findall(r"(https?://[^\s]+)", user_prompt_clean)
        has_files = "<context>" in raw_text

        if urls:
            extra_context += (
                f"\n\n[Контент со страницы {urls[0]}]:\n{self._fetch_web_page(urls[0])}"
            )
            # ИСПРАВЛЕНИЕ: Не перезаписываем intent на SEARCH, если это явно CODE или IMAGE
            if intent not in ["CODE", "IMAGE", "PRESENTATION"]:
                intent = "SEARCH"
        elif intent == "SEARCH":
            extra_context += f"\n\n[Данные из поиска]:\n{self._search_web(user_prompt_clean, valves.SEARXNG_URL)}"
        elif has_files:
            file_matches = re.findall(
                r"<(context|source).*?>(.*?)</\1>", raw_text, flags=re.DOTALL
            )
            relevant_files = []
            query_words = {w.lower() for w in user_prompt_clean.split() if len(w) > 3}
            for _, file_text in file_matches:
                file_lower = file_text.lower()
                # ИСПРАВЛЕНИЕ: Если слов в запросе нет (отправлен только файл), прикрепляем файл
                if not query_words or any(word in file_lower for word in query_words):
                    relevant_files.append(file_text.strip())

            for text in relevant_files:
                extra_context += f"\n\n[Содержимое прикрепленного файла]:\n{text}"

        # === РИСОВАНИЕ ===
        if intent == "IMAGE":

            def img_pipeline():
                prompt = user_prompt_clean
                if has_img:
                    yield "🔍 Изучаю референс...\n\n"
                    desc = self._ask_vision_internally(
                        valves,
                        messages,
                        "Describe this image in detail for use as an image generation reference.",
                    )
                    prompt = f"{desc}. Style: {user_prompt_clean}"

                yield f"🎨 Генерирую изображение: *{user_prompt_clean[:80]}*...\n\n"

                try:
                    res = requests.post(
                        f"{valves.MWS_BASE_URL}/images/generations",
                        headers={"Authorization": f"Bearer {valves.MWS_API_KEY}"},
                        json={
                            "model": valves.IMAGE_MODEL,
                            "prompt": prompt,
                            "size": "1024x1024",
                        },
                        timeout=120,
                    )
                    data = res.json()
                    if "data" in data and data["data"]:
                        img_url = data["data"][0].get("url") or data["data"][0].get(
                            "b64_json", ""
                        )
                        if img_url.startswith("http"):
                            yield f"![Result]({img_url})\n\n---\n> **Pipeline:** IMAGE → {valves.IMAGE_MODEL}"
                        elif img_url:
                            yield f"![Result](data:image/png;base64,{img_url})\n\n---\n> **Pipeline:** IMAGE → {valves.IMAGE_MODEL}"
                        else:
                            yield f"❌ Ошибка: изображение не содержит URL. Ответ API: {res.text[:300]}"
                    else:
                        yield f"❌ Ошибка генерации изображения: {res.text[:300]}"
                except requests.exceptions.Timeout:
                    yield "❌ Таймаут: сервер генерации не ответил за 120 секунд. Попробуйте ещё раз."
                except requests.exceptions.ConnectionError as e:
                    yield f"❌ Ошибка соединения с API генерации изображений: {str(e)}"
                except Exception as e:
                    yield f"❌ Неожиданная ошибка: {str(e)}"

            return img_pipeline()

        # === ВЫБОР МОДЕЛИ ===
        if intent == "VISION_DESCRIBE" or (
            has_img and intent not in ["CODE", "SEARCH"]
        ):
            body["model"] = valves.VISION_MODEL
        elif intent == "CODE" and has_img:
            body["model"] = valves.VISION_MODEL
        elif not has_img:
            mapping = {
                "CODE": valves.CODE_MODEL,
                "SEARCH": valves.SEARCH_MODEL,
                "TEXT": valves.TEXT_MODEL,
            }
            body["model"] = mapping.get(intent, valves.TEXT_MODEL)
        else:
            body["model"] = valves.VISION_MODEL

        # === ЧИСТИМ ИСТОРИЮ ===
        clean_messages = []
        for m in messages:
            content = m.get("content", "")
            if isinstance(content, list):
                new_content = []
                for item in content:
                    if item.get("type") == "text":
                        cleaned = self._clean_junk(item.get("text", ""))
                        # ИСПРАВЛЕНИЕ: Сохраняем пробел, чтобы не потерять сообщение с файлом
                        if not cleaned and m == messages[-1]:
                            cleaned = " "
                        if cleaned:
                            new_content.append({"type": "text", "text": cleaned})
                    elif item.get("type") == "image_url":
                        if body["model"] == valves.VISION_MODEL:
                            new_content.append(item)
                if new_content:
                    clean_messages.append({"role": m["role"], "content": new_content})
            else:
                cleaned_text = self._clean_junk(content)
                # ИСПРАВЛЕНИЕ: Сохраняем пробел, чтобы не потерять сообщение с файлом
                if not cleaned_text and m == messages[-1]:
                    cleaned_text = " "
                if cleaned_text:
                    clean_messages.append({"role": m["role"], "content": cleaned_text})

        body["messages"] = clean_messages
        # Инъекция памяти в системный промпт
        if memory_context:
            if clean_messages and clean_messages[0]["role"] == "system":
                existing = clean_messages[0].get("content", "")
                if isinstance(existing, str):
                    clean_messages[0]["content"] = memory_context + "\n\n" + existing
            else:
                clean_messages.insert(0, {"role": "system", "content": memory_context})
            body["messages"] = clean_messages

        if intent in ("SEARCH", "VISION_DESCRIBE") or (
            intent == "SEARCH" and extra_context
        ):
            search_system = (
                "ВАЖНО: Ты русскоязычный ИИ-ассистент. "
                "СТРОГОЕ ПРАВИЛО: отвечай ИСКЛЮЧИТЕЛЬНО на русском языке. "
                "Никогда не переключайся на английский, испанский, португальский или любой другой язык. "
                "Даже если предоставленные данные на иностранном языке — твой ответ всегда на русском. "
                "Отвечай кратко и по существу вопроса пользователя. "
                "Не пересказывай весь контент страницы — только то, о чём спросили."
            )
            if clean_messages and clean_messages[0]["role"] == "system":
                existing = clean_messages[0].get("content", "")
                if isinstance(existing, str):
                    clean_messages[0]["content"] = existing + "\n\n" + search_system
            else:
                clean_messages.insert(0, {"role": "system", "content": search_system})
            body["messages"] = clean_messages

        if extra_context and intent != "IMAGE" and len(body["messages"]) > 0:
            last_msg = body["messages"][-1]
            if isinstance(last_msg.get("content"), list):
                text_added = False
                for item in last_msg["content"]:
                    if item.get("type") == "text":
                        item["text"] += extra_context
                        text_added = True
                        break
                if not text_added:
                    last_msg["content"].append({"type": "text", "text": extra_context})
            else:
                last_msg["content"] += extra_context

        selected_model = body["model"]
        footer = f"\n\n---\n> **GPTHub Core:** {selected_model}"

        # ================================================================
        # КЛЮЧЕВОЕ ИСПРАВЛЕНИЕ: если память включена — стримим через обёртку,
        # которая после последнего chunk запускает extract_from_exchange.
        # Пользователь не ждёт — извлечение идёт в фоновом треде.
        # ================================================================
        if valves.MEMORY_ENABLED and mem and user_id:
            return self._stream_and_save_memory(
                valves,
                mem,
                user_id,
                user_prompt_clean,
                valves.MWS_BASE_URL,
                valves.MWS_API_KEY,
                body,
                footer,
            )

        return self.stream_response(
            valves.MWS_BASE_URL, valves.MWS_API_KEY, body, footer
        )

    def _stream_and_save_memory(
        self, valves, mem, user_id, user_message, url, key, body, footer
    ):
        """
        Стримит ответ как обычно, но накапливает текст.
        После последнего chunk запускает extract_from_exchange в фоне.
        Это гарантирует сохранение фактов даже из первого и единственного
        обмена в чате — в отличие от старого подхода где extraction
        происходила в начале СЛЕДУЮЩЕГО запроса.
        """
        response_parts = []

        for chunk in self.stream_response(url, key, body, footer):
            response_parts.append(chunk)
            yield chunk

        # После стрима — запускаем сохранение в фоне (не блокирует UI)
        try:
            full_response = "".join(response_parts)
            # Убираем футер из текста перед анализом
            clean_response = re.sub(
                r"\n\n---\n>.*$", "", full_response, flags=re.DOTALL
            ).strip()

            if clean_response and user_message:
                mem.extract_from_exchange(
                    user_id=user_id,
                    api_key=valves.MWS_API_KEY,
                    base_url=valves.MWS_BASE_URL,
                    router_model=valves.ROUTER_MODEL,
                    user_message=user_message,
                    assistant_message=clean_response,
                )
        except Exception:
            pass  # Ошибки памяти не ломают UX

    def stream_response(self, url, key, body, footer):
        headers = {"Authorization": f"Bearer {key}", "Content-Type": "application/json"}
        try:
            with requests.post(
                f"{url}/chat/completions", headers=headers, json=body, stream=True
            ) as r:
                if r.status_code != 200:
                    yield f"❌ **Ошибка API:** {r.text}"
                    return
                for line in r.iter_lines():
                    if line:
                        line = line.decode("utf-8").replace("data: ", "")
                        if line == "[DONE]":
                            break
                        try:
                            content = json.loads(line)["choices"][0]["delta"].get(
                                "content", ""
                            )
                            yield content
                        except Exception:
                            continue
                yield footer
        except Exception as e:
            yield f"Ошибка: {str(e)}"
